function freq(arr, sm) {
  const c = {};
  arr.forEach(v => { if (v) c[v] = (c[v] || 0) + 1; });
  const tot = arr.filter(Boolean).length || 1;
  return Object.entries(c).sort((a,b) => b[1]-a[1])
    .map(([k,n]) => ({ key:k, label:(sm&&sm[k])||k, n, pct:Math.round(n/tot*100) }));
}
function mfreq(rows, fld) {
  const c = {};
  rows.forEach(r => { (r[fld]||[]).forEach(v => { if(v) c[v]=(c[v]||0)+1; }); });
  const tot = rows.length || 1;
  return Object.entries(c).sort((a,b) => b[1]-a[1])
    .map(([k,n]) => ({ key:k, label:k, n, pct:Math.round(n/tot*100) }));
}
function ht(s, n=30) { s=String(s||""); return s.length>n ? s.slice(0,n-1)+"…" : s; }

function getSuggestions(q) {
  if (!q || q.length < 2) return [];
  const ql = q.toLowerCase();
  const results = [];
  for (const fd of FILTERS) {
    const getDisp = o => (fd.display&&fd.display[o]) || o;
    const matchOpts = fd.opts.filter(o => getDisp(o).toLowerCase().includes(ql) || String(o).toLowerCase().includes(ql));
    const inAlias = fd.aliases.some(a => a.includes(ql) || ql.includes(a.split(" ")[0]));
    if (matchOpts.length) matchOpts.slice(0,3).forEach(o => results.push({fd, value:o, score:3}));
    else if (inAlias) fd.opts.slice(0,3).forEach(o => results.push({fd, value:o, score:2}));
  }
  results.sort((a,b) => b.score-a.score);
  const seen = new Set();
  return results.filter(r => { const k=r.fd.key+":"+r.value; if(seen.has(k))return false; seen.add(k); return true; }).slice(0,9);
}

function applyFilter(F, fd, val) {
  const next = {...F};
  if (fd.multi) {
    const cur = next[fd.key];
    if (Array.isArray(cur)) {
      const updated = cur.includes(val) ? cur.filter(x=>x!==val) : [...cur, val];
      if (updated.length) next[fd.key] = updated; else delete next[fd.key];
    } else next[fd.key] = [val];
  } else {
    if (next[fd.key] === val) delete next[fd.key]; else next[fd.key] = val;
  }
  return next;
}

function removeFromFilter(F, k, val) {
  const next = {...F};
  if (Array.isArray(next[k])) {
    const updated = next[k].filter(x => x !== val);
    if (updated.length) next[k] = updated; else delete next[k];
  } else delete next[k];
  return next;
}

function filterData(F, activeSegs) {
  let rows = D;
  for (const [k,v] of Object.entries(F)) {
    if (!v || (Array.isArray(v) && !v.length)) continue;
    rows = rows.filter(r => {
      if (Array.isArray(v)) return v.some(fv => Array.isArray(r[k]) ? r[k].includes(fv) : r[k]===fv);
      return Array.isArray(r[k]) ? r[k].includes(v) : r[k]===v;
    });
  }
  if (activeSegs.size > 0) rows = rows.filter(r => [...activeSegs].every(i => SEG_DEFS[i].fn(r)));
  return rows;
}

function nBadge(n) {
  if (n < 10) return <span style={{fontSize:10,padding:"2px 6px",borderRadius:20,background:"#FEE2E2",color:"#991B1B",fontWeight:500,whiteSpace:"nowrap"}}>n={n}</span>;
  if (n < 30) return <span style={{fontSize:10,padding:"2px 6px",borderRadius:20,background:"#FEF3C7",color:"#92400E",fontWeight:500,whiteSpace:"nowrap"}}>n={n}</span>;
  return <span style={{fontSize:10,padding:"2px 6px",borderRadius:20,background:"#D1FAE5",color:"#065F46",fontWeight:500,whiteSpace:"nowrap"}}>n={n}</span>;
}

function BarChart({ items, title, color, fdkey, isMulti, maxShow=8, v8only, cmpItems, showFullQ, countMode, onFilter, n, cmpN, onPin, cmpMode }) {
  const shown = items.slice(0, maxShow);
  const maxP = Math.max(shown[0]?.pct||1, cmpItems&&cmpItems.length?cmpItems[0].pct:0, 1);
  const fullQ = QT[fdkey]||"";
  function valDisp(item, total) {
    if (countMode==="pct") return item.pct+"%";
    if (countMode==="count") return String(item.n);
    return item.pct+"% ("+item.n+")";
  }
  return (
    <div style={{background:"var(--bg,#fff)",border:"0.5px solid var(--bd,#e2e2e2)",borderRadius:12,padding:14}}>
      <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",marginBottom:10,gap:8}}>
        <h4 style={{fontSize:12.5,fontWeight:500,flex:1,lineHeight:1.4,margin:0,display:"flex",alignItems:"center",gap:6}}>
          {showFullQ && fullQ ? fullQ : title}
          {v8only && <span style={{fontSize:10,background:"#10B981",color:"#fff",padding:"2px 6px",borderRadius:20}}>Online/Hybrid (2)</span>}
        </h4>
        <div style={{display:"flex",alignItems:"center",gap:4,flexShrink:0}}>
          {nBadge(n)}
          {!cmpMode && <button onClick={onPin} style={{fontSize:10,padding:"2px 7px",border:"0.5px solid var(--bd2,#ccc)",borderRadius:6,cursor:"pointer",background:"var(--bg2,#f7f7f7)",color:"var(--tx2,#555)",fontFamily:"inherit"}}>Pin A</button>}
        </div>
      </div>
      {shown.map((item, idx) => {
        const disp = DISPLAY_SM[item.label] || (showFullQ ? item.label : ht(item.label, 30));
        const isOn = isMulti ? (Array.isArray(onFilter) && onFilter.includes(item.key)) : onFilter===item.key;
        const w = Math.round(item.pct/maxP*100);
        const cmpItem = cmpItems?.find(c => c.key===item.key);
        const cmpW = cmpItem ? Math.round(cmpItem.pct/maxP*100) : 0;
        const delta = cmpItem ? item.pct - cmpItem.pct : 0;
        const highlight = Math.abs(delta) >= 10;
        return (
          <div key={item.key} onClick={() => {}} style={{display:"flex",alignItems:"center",gap:6,marginBottom:4,cursor:"pointer",borderRadius:4,padding:"2px 3px",background:isOn?"var(--inxl,#EEEEFE)":"transparent"}}
            onMouseEnter={e=>e.currentTarget.style.background="var(--inxl,#EEEEFE)"}
            onMouseLeave={e=>e.currentTarget.style.background=isOn?"var(--inxl,#EEEEFE)":"transparent"}
            onClick={() => onFilter(item.key)}>
            <div style={{fontSize:11,color:highlight?(delta>0?"#5046E5":"#EF4444"):"var(--tx2,#555)",flexShrink:0,lineHeight:1.3,width:158,fontWeight:highlight?500:400}} title={item.key}>{disp}</div>
            <div style={{flex:1,background:"var(--bg3,#f0f0f0)",borderRadius:3,overflow:"hidden",display:"flex",flexDirection:"column",gap:1,height:cmpItem?15:14}}>
              <div style={{height:cmpItem?8:14,width:w+"%",background:color,borderRadius:3,transition:"width .3s"}}/>
              {cmpItem && <div style={{height:5,width:cmpW+"%",background:color,opacity:.4,borderRadius:3,transition:"width .3s"}}/>}
            </div>
            <div style={{fontSize:10.5,color:"var(--tx3,#999)",width:cmpItem?58:30,textAlign:"right",flexShrink:0,lineHeight:1.3}}>
              {valDisp(item,n)}
              {cmpItem && <div style={{opacity:.55,fontSize:9.5}}>{valDisp(cmpItem,cmpN||n)}</div>}
            </div>
          </div>
        );
      })}
      {cmpItems && <div style={{display:"flex",alignItems:"center",gap:8,marginTop:6,fontSize:11,color:"var(--tx3,#999)"}}>
        <span style={{display:"inline-block",width:20,height:7,borderRadius:2,background:color,opacity:.9}}/>Current
        <span style={{display:"inline-block",width:20,height:5,borderRadius:2,background:color,opacity:.4}}/>Group A
      </div>}
    </div>
  );
}

function PieChart({ items, title, fdkey, sm, cmpItems, showFullQ, countMode, onFilter, currentVal, n, cmpN, onPin, cmpMode }) {
  const shown = items.slice(0, 6);
  const fullQ = QT[fdkey]||"";
  const sz=110, cx=55, cy=55, r=48;
  let ang = -Math.PI/2;
  const slices = shown.map((item,i) => {
    const a = (item.pct/100)*2*Math.PI;
    const ea = ang+a;
    const x1=(cx+Math.cos(ang)*r).toFixed(1), y1=(cy+Math.sin(ang)*r).toFixed(1);
    const x2=(cx+Math.cos(ea)*r).toFixed(1), y2=(cy+Math.sin(ea)*r).toFixed(1);
    const lg = a>Math.PI?1:0;
    const d = `M${cx},${cy}L${x1},${y1}A${r},${r} 0 ${lg},1 ${x2},${y2}Z`;
    const on = currentVal===item.key;
    const cmpItem = cmpItems?.find(c=>c.key===item.key);
    ang = ea;
    return { d, c:P[i], item, on, cmpItem };
  });
  function valDisp(item,tot) {
    if (countMode==="pct") return item.pct+"%";
    if (countMode==="count") return String(item.n);
    return item.pct+"% ("+item.n+")";
  }
  const disp = item => (sm&&sm[item.key]) || (showFullQ ? item.label : ht(item.label, 26));
  return (
    <div style={{background:"var(--bg,#fff)",border:"0.5px solid var(--bd,#e2e2e2)",borderRadius:12,padding:14}}>
      <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",marginBottom:10,gap:8}}>
        <h4 style={{fontSize:12.5,fontWeight:500,flex:1,lineHeight:1.4,margin:0}}>{showFullQ&&fullQ?fullQ:title}</h4>
        <div style={{display:"flex",alignItems:"center",gap:4,flexShrink:0}}>
          {nBadge(n)}
          {!cmpMode && <button onClick={onPin} style={{fontSize:10,padding:"2px 7px",border:"0.5px solid var(--bd2,#ccc)",borderRadius:6,cursor:"pointer",background:"var(--bg2,#f7f7f7)",color:"var(--tx2,#555)",fontFamily:"inherit"}}>Pin A</button>}
        </div>
      </div>
      <div style={{display:"flex",gap:12,alignItems:"flex-start",flexWrap:"wrap"}}>
        <svg width={sz} height={sz} style={{flexShrink:0}}>
          {slices.map((s,i) => (
            <path key={i} d={s.d} fill={s.c} opacity={s.on?1:.83} stroke="#fff" strokeWidth={1.5}
              style={{cursor:"pointer"}} onClick={() => onFilter(s.item.key)}/>
          ))}
        </svg>
        <div style={{display:"flex",flexDirection:"column",gap:3}}>
          {slices.map((s,i) => {
            const delta = s.cmpItem ? s.item.pct - s.cmpItem.pct : 0;
            const highlight = Math.abs(delta) >= 10;
            return (
              <div key={i} onClick={() => onFilter(s.item.key)}
                style={{display:"flex",alignItems:"center",gap:5,cursor:"pointer",padding:"2px 4px",borderRadius:4,background:s.on?"var(--inxl,#EEEEFE)":"transparent"}}
                onMouseEnter={e=>e.currentTarget.style.background="var(--inxl,#EEEEFE)"}
                onMouseLeave={e=>e.currentTarget.style.background=s.on?"var(--inxl,#EEEEFE)":"transparent"}>
                <div style={{width:8,height:8,borderRadius:"50%",background:s.c,flexShrink:0}}/>
                <strong style={{fontSize:11.5,color:highlight?(delta>0?"#5046E5":"#EF4444"):"var(--tx,#111)"}}>{valDisp(s.item,n)}</strong>
                {s.cmpItem && <span style={{fontSize:9.5,color:"var(--tx3,#999)",marginLeft:2}}>vs {valDisp(s.cmpItem,cmpN||n)}</span>}
                <span style={{fontSize:11,color:"var(--tx2,#555)",maxWidth:120,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}} title={s.item.key}>{disp(s.item)}</span>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

export default function App() {
  const [F, setF] = useState({});
  const [activeSegs, setActiveSegs] = useState(new Set());
  const [searchVal, setSearchVal] = useState("");
  const [showSug, setShowSug] = useState(false);
  const [showFullQ, setShowFullQ] = useState(false);
  const [countMode, setCountMode] = useState("pct");
  const [cmpMode, setCmpMode] = useState(false);
  const [cmpRows, setCmpRows] = useState(null);
  const [cmpLabel, setCmpLabel] = useState("");
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [drawerSearch, setDrawerSearch] = useState("");
  const [qaInput, setQaInput] = useState("");
  const [qaAnswer, setQaAnswer] = useState("");
  const [qaLoading, setQaLoading] = useState(false);
  const searchRef = useRef(null);
  const searchTimer = useRef(null);

  const rows = filterData(F, activeSegs);
  const n = rows.length;
  const v5n = rows.filter(r=>r.survey==="v5").length;
  const v8n = rows.filter(r=>r.survey==="v8").length;
  const ages = rows.map(r=>r.age).filter(Boolean).sort((a,b)=>a-b);
  const medAge = ages.length ? ages[Math.floor(ages.length/2)] : "--";
  const hi = rows.filter(r=>r.budget&&(r.budget.includes("$1,000")||r.budget.includes("$3,000")||r.budget.includes("$5,000")||r.budget.includes("Over"))).length;
  const female = rows.filter(r=>r.gender==="Female").length;

  const cmpData = cmpMode && cmpRows ? {
    gut: freq(cmpRows.map(r=>r.gut)), ad_status: freq(cmpRows.map(r=>r.ad_status)),
    budget: freq(cmpRows.map(r=>r.budget)), ai_attitude: freq(cmpRows.map(r=>r.ai_attitude)),
    hard_parts: mfreq(cmpRows,"hard_parts"), worries: mfreq(cmpRows,"worries"),
    channels: mfreq(cmpRows,"channels"), tried_channels: mfreq(cmpRows,"tried_channels"),
    success_def: mfreq(cmpRows.filter(r=>r.survey==="v8"),"success_def"),
    industry: freq(cmpRows.map(r=>r.industry)), nature_affects: freq(cmpRows.filter(r=>r.nature_affects).map(r=>r.nature_affects)),
    involvement: freq(cmpRows.map(r=>r.involvement)), tenure: freq(cmpRows.map(r=>r.tenure)),
    revenue: freq(cmpRows.map(r=>r.revenue)), operation: freq(cmpRows.map(r=>r.operation)),
    region: freq(cmpRows.map(r=>r.region)),
  } : {};
  const cmp = k => cmpMode ? (cmpData[k]||null) : null;
  const cmpN = cmpRows?.length;

  function handleFilter(fdkey, val) {
    const fd = FILTERS.find(f=>f.key===fdkey);
    if (fd) setF(prev => applyFilter(prev, fd, val));
  }
  function handleRemovePill(k, val) { setF(prev => removeFromFilter(prev, k, val)); }
  function handleSegToggle(i) {
    setActiveSegs(prev => { const n=new Set(prev); n.has(i)?n.delete(i):n.add(i); return n; });
  }
  function handleClearAll() { setF({}); setActiveSegs(new Set()); }
  function handlePin() {
    const r = filterData(F, activeSegs);
    const segs = [...activeSegs].map(i=>SEG_DEFS[i].label);
    const filters = Object.entries(F).filter(([,v])=>v).map(([k,v])=>Array.isArray(v)?v.join(", "):v);
    setCmpRows(r);
    setCmpLabel((segs.concat(filters).join(" + ")||"All respondents")+` (n=${r.length})`);
    setCmpMode(true);
  }
  function handleClearCmp() { setCmpMode(false); setCmpRows(null); setCmpLabel(""); }

  const sugs = getSuggestions(searchVal);

  // Q&A via built-in Claude API
  async function handleAsk() {
    if (!qaInput.trim()) return;
    setQaLoading(true); setQaAnswer("");
    function fqs(arr) { const c={}; arr.forEach(v=>{if(v)c[v]=(c[v]||0)+1;}); const tot=arr.filter(Boolean).length||1; return Object.entries(c).sort((a,b)=>b[1]-a[1]).slice(0,8).map(([k,ct])=>k+": "+Math.round(ct/tot*100)+"%").join("; "); }
    function mfqs(rows,fld) { const c={}; rows.forEach(r=>{(r[fld]||[]).forEach(v=>{if(v)c[v]=(c[v]||0)+1;})}); const tot=rows.length||1; return Object.entries(c).sort((a,b)=>b[1]-a[1]).slice(0,8).map(([k,ct])=>k+": "+Math.round(ct/tot*100)+"%").join("; "); }
    const v8r = rows.filter(r=>r.survey==="v8");
    const oeSnippets = rows.filter(r=>r.open_ended&&String(r.open_ended).trim().toLowerCase()!=="n/a").slice(0,10).map(r=>String(r.open_ended)).join(" | ");
    const sys = `You analyze ad101 SMB advertising survey data. n=${n} of ${D.length} respondents shown. Active filters: ${JSON.stringify(F)}.
Gut: ${fqs(rows.map(r=>r.gut))} | Status: ${fqs(rows.map(r=>r.ad_status))} | Budget: ${fqs(rows.map(r=>r.budget))} | AI: ${fqs(rows.map(r=>r.ai_attitude))}
Industry: ${fqs(rows.map(r=>r.industry))} | Region: ${fqs(rows.map(r=>r.region))} | Revenue: ${fqs(rows.map(r=>r.revenue))} | Tenure: ${fqs(rows.map(r=>r.tenure))}
Hard parts: ${mfqs(rows,"hard_parts")} | Worries: ${mfqs(rows,"worries")} | Channels: ${mfqs(rows,"channels")} | Tried: ${mfqs(rows,"tried_channels")}
Success (v8 n=${v8r.length}): ${mfqs(v8r,"success_def")} | Nature affects: ${fqs(v8r.map(r=>r.nature_affects))} | Involvement: ${fqs(rows.map(r=>r.involvement))}
Sample open-ended: ${oeSnippets}
Answer in 2-4 sentences. Be specific with numbers. No em dashes. No markdown.`;
    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method:"POST",
        headers:{"Content-Type":"application/json","anthropic-version":"2023-06-01"},
        body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:400,system:sys,messages:[{role:"user",content:qaInput}]})
      });
      const d = await res.json();
      setQaAnswer(d.error?"Error: "+d.error.message:(d.content?.[0]?.text||"No response."));
    } catch(e) { setQaAnswer("Error: "+e.message); }
    setQaLoading(false);
  }

  function exportSummary() {
    function fqs(arr,mx=3){const c={};arr.forEach(v=>{if(v)c[v]=(c[v]||0)+1;});const tot=arr.filter(Boolean).length||1;return Object.entries(c).sort((a,b)=>b[1]-a[1]).slice(0,mx).map(([k,ct])=>k+" ("+Math.round(ct/tot*100)+"%)").join(", ");}
    function mfqs(rows,fld,mx=3){const c={};rows.forEach(r=>{(r[fld]||[]).forEach(v=>{if(v)c[v]=(c[v]||0)+1;});});const tot=rows.length||1;return Object.entries(c).sort((a,b)=>b[1]-a[1]).slice(0,mx).map(([k,ct])=>k+" ("+Math.round(ct/tot*100)+"%)").join(", ");}
    const txt = `ad101 Survey Snapshot — ${new Date().toLocaleDateString()}
Segment: ${Object.entries(F).filter(([,v])=>v).map(([k,v])=>k+": "+JSON.stringify(v)).join(", ")||[...activeSegs].map(i=>SEG_DEFS[i].label).join(", ")||"Full sample"}
n=${n} (Original SMB (1): ${v5n}, Online/Hybrid (2): ${v8n})

Gut reaction: ${fqs(rows.map(r=>r.gut))}
Ad status: ${fqs(rows.map(r=>r.ad_status))}
Budget: ${fqs(rows.map(r=>r.budget))}
AI attitude: ${fqs(rows.map(r=>r.ai_attitude))}
Hardest parts: ${mfqs(rows,"hard_parts")}
Worries: ${mfqs(rows,"worries")}
Current channels: ${mfqs(rows,"channels")}
Industry: ${fqs(rows.map(r=>r.industry))}
Revenue: ${fqs(rows.map(r=>r.revenue))}`;
    navigator.clipboard.writeText(txt).catch(()=>{});
    return txt;
  }

  // Pills
  const pills = Object.entries(F).flatMap(([k,v]) => {
    if (!v||(Array.isArray(v)&&!v.length)) return [];
    const fd = FILTERS.find(f=>f.key===k);
    const vals = Array.isArray(v)?v:[v];
    return vals.map(val => ({ k, val, disp:(fd?.display?.[val])||ht(val,26) }));
  });

  const insight = () => {
    const conf=rows.filter(r=>r.gut&&r.gut.includes("confident")).length;
    const active=rows.filter(r=>r.ad_status&&r.ad_status.includes("actively")).length;
    const burned=rows.filter(r=>r.ad_status&&r.ad_status.includes("wasting")).length;
    const hiPct=n?Math.round(hi/n*100):0;
    const aipos=rows.filter(r=>r.ai_attitude&&(r.ai_attitude.includes("Open to it")||r.ai_attitude.includes("comfortable"))).length;
    return [
      <span key="c"><b>{Math.round(conf/n*100)}%</b> feel confident</span>,
      <span key="a"> · <b>{Math.round(active/n*100)}%</b> actively advertising, want better results</span>,
      burned?<span key="b"> · <b>{Math.round(burned/n*100)}%</b> tried and felt burned</span>:null,
      <span key="h"> · <b>{hiPct}%</b> spend $1K+/month</span>,
      <span key="ai"> · <b>{Math.round(aipos/n*100)}%</b> open to or using AI</span>,
    ].filter(Boolean);
  };

  const chartProps = (fdkey, isMulti) => ({
    fdkey, isMulti, showFullQ, countMode, n, cmpN, cmpMode,
    onFilter: (val) => handleFilter(fdkey, val),
    onPin: handlePin,
    currentVal: F[fdkey],
    onFilter: (val) => handleFilter(fdkey, val),
  });

  const oeResponses = rows.filter(r=>r.open_ended&&String(r.open_ended).trim().toLowerCase()!=="n/a"&&String(r.open_ended).trim()!=="");
  const filteredOe = drawerSearch ? oeResponses.filter(r=>String(r.open_ended).toLowerCase().includes(drawerSearch.toLowerCase())) : oeResponses;

  const btnStyle = (on) => ({fontSize:11,padding:"3px 9px",border:"0.5px solid var(--bd2,#ccc)",borderRadius:20,cursor:"pointer",background:on?"#5046E5":"var(--bg2,#f7f7f7)",color:on?"#fff":"var(--tx2,#555)",fontFamily:"inherit"});
  const toolBtnStyle = {fontSize:12,padding:"5px 12px",border:"0.5px solid var(--bd2,#ccc)",borderRadius:8,cursor:"pointer",background:"var(--bg2,#f7f7f7)",color:"var(--tx2,#555)",fontFamily:"inherit"};

  return (
    <div style={{maxWidth:1400,margin:"0 auto",padding:14,fontFamily:"-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif",fontSize:13,color:"var(--tx,#111)",background:"var(--bg3,#f0f0f0)",minHeight:"100vh"}}>

      {/* Top bar */}
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",background:"var(--bg,#fff)",border:"0.5px solid var(--bd,#e2e2e2)",borderRadius:12,padding:"11px 16px",marginBottom:12,gap:10,flexWrap:"wrap"}}>
        <div style={{fontSize:15,fontWeight:600}}><em style={{color:"#5046E5",fontStyle:"normal"}}>ad101</em> survey explorer</div>
        <div style={{display:"flex",gap:8,alignItems:"center",flexWrap:"wrap"}}>
          <button onClick={exportSummary} style={toolBtnStyle}>⬇ Export</button>
          <button onClick={()=>setDrawerOpen(o=>!o)} style={{...toolBtnStyle,background:drawerOpen?"#5046E5":"var(--bg2,#f7f7f7)",color:drawerOpen?"#fff":"var(--tx2,#555)"}}>☰ Responses ({oeResponses.length})</button>
        </div>
      </div>

      {/* Comparison banner */}
      {cmpMode && <div style={{background:"#FEF3C7",border:"0.5px solid #F59E0B",borderRadius:8,padding:"7px 13px",marginBottom:10,fontSize:12,color:"#92400E",display:"flex",alignItems:"center",flexWrap:"wrap",gap:6}}>
        <span>Comparing against <strong>{cmpLabel}</strong> — bars highlighted where groups differ 10+ points</span>
        <button onClick={handleClearCmp} style={{fontSize:11,padding:"2px 8px",border:"0.5px solid #F59E0B",borderRadius:6,cursor:"pointer",background:"transparent",color:"#92400E",fontFamily:"inherit",marginLeft:"auto"}}>✕ Exit comparison</button>
      </div>}

      {/* Filter builder */}
      <div style={{background:"var(--bg,#fff)",border:"0.5px solid var(--bd,#e2e2e2)",borderRadius:12,padding:"12px 14px",marginBottom:12}}>
        <div style={{position:"relative",marginBottom:10}}>
          <span style={{position:"absolute",left:10,top:"50%",transform:"translateY(-50%)",color:"var(--tx3,#999)",pointerEvents:"none",fontSize:14}}>⌕</span>
          <input
            ref={searchRef}
            value={searchVal}
            onChange={e => { setSearchVal(e.target.value); clearTimeout(searchTimer.current); searchTimer.current=setTimeout(()=>setShowSug(true),100); }}
            onFocus={() => setShowSug(true)}
            onBlur={() => setTimeout(()=>setShowSug(false), 200)}
            placeholder="Search filters — try 'healthcare', 'burned', 'high spend', 'Google Ads'..."
            style={{width:"100%",fontSize:13,padding:"7px 12px 7px 32px",border:"1px solid var(--bd2,#ccc)",borderRadius:8,background:"var(--bg,#fff)",color:"var(--tx,#111)",outline:"none"}}
          />
          {showSug && sugs.length > 0 && (
            <div style={{position:"absolute",top:"calc(100% + 3px)",left:0,right:0,background:"var(--bg,#fff)",border:"0.5px solid var(--bd2,#ccc)",borderRadius:8,boxShadow:"0 4px 16px rgba(0,0,0,.12)",zIndex:100,maxHeight:240,overflowY:"auto"}}>
              {sugs.map((s,i) => {
                const disp = (s.fd.display&&s.fd.display[s.value]) || s.value;
                return <div key={i} onMouseDown={() => { const fd=s.fd; setF(prev=>applyFilter(prev,fd,s.value)); setSearchVal(""); setShowSug(false); }}
                  style={{padding:"7px 12px",cursor:"pointer",display:"flex",alignItems:"center",gap:8,fontSize:12}}
                  onMouseEnter={e=>e.currentTarget.style.background="var(--inxl,#EEEEFE)"}
                  onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                  <span style={{fontSize:10,padding:"2px 6px",borderRadius:10,background:"var(--bg2,#f7f7f7)",color:"var(--tx3,#999)",flexShrink:0}}>{s.fd.cat}</span>
                  <span>{ht(disp,44)}</span>
                </div>;
              })}
            </div>
          )}
        </div>
        <div style={{display:"flex",gap:6,flexWrap:"wrap",alignItems:"center"}}>
          <span style={{fontSize:11,color:"var(--tx3,#999)",whiteSpace:"nowrap"}}>Quick segments:</span>
          {SEG_DEFS.map((seg,i) => (
            <button key={i} onClick={()=>handleSegToggle(i)} style={btnStyle(activeSegs.has(i))}>{seg.label}</button>
          ))}
        </div>
      </div>

      {/* Active pills */}
      {(pills.length>0||activeSegs.size>0) && (
        <div style={{display:"flex",flexWrap:"wrap",gap:5,alignItems:"center",marginBottom:10}}>
          {pills.map((p,i) => (
            <button key={i} onClick={()=>handleRemovePill(p.k,p.val)}
              style={{display:"inline-flex",alignItems:"center",gap:4,fontSize:11,padding:"3px 9px",background:"var(--inxl,#EEEEFE)",color:"#5046E5",borderRadius:20,cursor:"pointer",border:"none",fontFamily:"inherit"}}>
              ✕ {p.disp}
            </button>
          ))}
          {[...activeSegs].map(i => (
            <button key={i} onClick={()=>handleSegToggle(i)}
              style={{display:"inline-flex",alignItems:"center",gap:4,fontSize:11,padding:"3px 9px",background:"var(--inxl,#EEEEFE)",color:"#5046E5",borderRadius:20,cursor:"pointer",border:"none",fontFamily:"inherit"}}>
              ✕ {SEG_DEFS[i].label}
            </button>
          ))}
          <button onClick={handleClearAll} style={{display:"inline-flex",alignItems:"center",gap:4,fontSize:11,padding:"3px 9px",background:"transparent",color:"var(--tx3,#999)",borderRadius:20,cursor:"pointer",border:"0.5px solid var(--bd,#e2e2e2)",fontFamily:"inherit"}}>Clear all</button>
          <span style={{fontSize:11,color:"var(--tx3,#999)"}}>{n} of {D.length} respondents</span>
        </div>
      )}

      {/* Display controls */}
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:12,flexWrap:"wrap",gap:6}}>
        <div style={{display:"flex",gap:5,flexWrap:"wrap"}}>
          {["pct","both","count"].map(m => <button key={m} onClick={()=>setCountMode(m)} style={btnStyle(countMode===m)}>{m==="pct"?"% only":m==="both"?"% + n":"n only"}</button>)}
          <button onClick={()=>setShowFullQ(q=>!q)} style={btnStyle(showFullQ)}>Full questions</button>
        </div>
        <div>
          {!cmpMode
            ? <button onClick={handlePin} style={btnStyle(false)}>Pin as Group A</button>
            : <button onClick={handleClearCmp} style={btnStyle(true)}>Exit comparison</button>}
        </div>
      </div>

      {/* Stats */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(6,1fr)",gap:8,marginBottom:12}}>
        {[
          [n,"respondents",`of ${D.length} total`],
          [v5n,"Original SMB (1)"],
          [v8n,"Online/Hybrid (2)"],
          [medAge,"median age"],
          [(n?Math.round(hi/n*100):0)+"%","spend $1K+/mo"],
          [(n?Math.round(female/n*100):0)+"%","female"],
        ].map(([v,l,s],i) => (
          <div key={i} style={{background:"var(--bg,#fff)",border:"0.5px solid var(--bd,#e2e2e2)",borderRadius:8,padding:"11px 13px"}}>
            <div style={{fontSize:24,fontWeight:600,color:"#5046E5"}}>{v}</div>
            <div style={{fontSize:11,color:"var(--tx2,#555)",marginTop:2}}>{l}</div>
            {s && <div style={{fontSize:10,color:"var(--tx3,#999)",marginTop:1}}>{s}</div>}
          </div>
        ))}
      </div>

      {/* Insight bar */}
      <div style={{background:"#5046E5",color:"#fff",borderRadius:8,padding:"9px 13px",marginBottom:12,fontSize:12,lineHeight:1.7}}>
        {n>0?insight():"No respondents match current filters."}
      </div>

      {/* Charts */}
      <div style={{display:"flex",flexDirection:"column",gap:12}}>

        {/* Q&A */}
        <div style={{background:"var(--bg,#fff)",border:"0.5px solid var(--bd,#e2e2e2)",borderRadius:12,padding:14}}>
          <h4 style={{fontSize:13,fontWeight:500,marginBottom:10}}>Ask about the data</h4>
          <div style={{display:"flex",gap:7}}>
            <input value={qaInput} onChange={e=>setQaInput(e.target.value)}
              onKeyDown={e=>e.key==="Enter"&&handleAsk()}
              placeholder="e.g. How do high spenders differ from the rest?"
              style={{flex:1,fontSize:13,padding:"7px 11px",border:"0.5px solid var(--bd2,#ccc)",borderRadius:8,background:"var(--bg,#fff)",color:"var(--tx,#111)",outline:"none"}}/>
            <button onClick={handleAsk} disabled={qaLoading}
              style={{fontSize:12,padding:"7px 14px",background:qaLoading?"var(--bd2,#ccc)":"#5046E5",color:"#fff",border:"none",borderRadius:8,cursor:qaLoading?"default":"pointer",fontWeight:500,fontFamily:"inherit"}}>
              {qaLoading?"…":"Ask"}
            </button>
          </div>
          <div style={{display:"flex",flexWrap:"wrap",gap:5,marginTop:8}}>
            {["How do high spenders differ?","What do healthcare businesses worry about?","Which industries feel most burned?","What channels do confident advertisers use?","How does AI attitude vary by budget?","What does success mean for Online/Hybrid respondents?"].map((q,i) => (
              <button key={i} onClick={()=>setQaInput(q)}
                style={{fontSize:11,padding:"3px 8px",border:"0.5px solid var(--bd,#e2e2e2)",borderRadius:20,cursor:"pointer",color:"var(--tx2,#555)",background:"var(--bg2,#f7f7f7)",fontFamily:"inherit"}}>
                {q}
              </button>
            ))}
          </div>
          {qaLoading && <div style={{color:"var(--tx3,#999)",fontStyle:"italic",fontSize:12,marginTop:8,display:"flex",alignItems:"center",gap:6}}>
            <div style={{width:14,height:14,border:"2px solid var(--bd2,#ccc)",borderTopColor:"#5046E5",borderRadius:"50%",animation:"spin .7s linear infinite",flexShrink:0}}/>
            Analyzing the filtered data…
          </div>}
          {qaAnswer && <div style={{marginTop:11,fontSize:13,lineHeight:1.75,borderLeft:"3px solid #5046E5",padding:"10px 12px",background:"var(--inxl,#EEEEFE)",borderRadius:"0 8px 8px 0"}}>{qaAnswer}</div>}
        </div>

        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
          <PieChart items={freq(rows.map(r=>r.gut))} title="Gut reaction" fdkey="gut" sm={GS} cmpItems={cmp("gut")} {...{showFullQ,countMode,n,cmpN,cmpMode,onPin:handlePin,currentVal:F.gut,onFilter:v=>handleFilter("gut",v)}}/>
          <PieChart items={freq(rows.map(r=>r.ad_status))} title="Advertising status" fdkey="ad_status" sm={SS} cmpItems={cmp("ad_status")} {...{showFullQ,countMode,n,cmpN,cmpMode,onPin:handlePin,currentVal:F.ad_status,onFilter:v=>handleFilter("ad_status",v)}}/>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
          <PieChart items={freq(rows.map(r=>r.budget))} title="Monthly budget" fdkey="budget" cmpItems={cmp("budget")} {...{showFullQ,countMode,n,cmpN,cmpMode,onPin:handlePin,currentVal:F.budget,onFilter:v=>handleFilter("budget",v)}}/>
          <PieChart items={freq(rows.map(r=>r.ai_attitude))} title="AI attitudes" fdkey="ai_attitude" sm={AS} cmpItems={cmp("ai_attitude")} {...{showFullQ,countMode,n,cmpN,cmpMode,onPin:handlePin,currentVal:F.ai_attitude,onFilter:v=>handleFilter("ai_attitude",v)}}/>
        </div>
        <BarChart items={mfreq(rows,"hard_parts")} title="Hardest parts of advertising" color="#5046E5" fdkey="hard_parts" isMulti maxShow={7} cmpItems={cmp("hard_parts")} {...{showFullQ,countMode,n,cmpN,cmpMode,onPin:handlePin,onFilter:v=>handleFilter("hard_parts",v)}}/>
        {v8n>0 && <BarChart items={mfreq(rows.filter(r=>r.survey==="v8"),"success_def")} title='What does "working" mean?' color="#10B981" fdkey="success_def" isMulti maxShow={8} v8only cmpItems={cmp("success_def")} {...{showFullQ,countMode,n:v8n,cmpN,cmpMode,onPin:handlePin,onFilter:v=>handleFilter("success_def",v)}}/>}
        <BarChart items={mfreq(rows,"worries")} title="Worries about paid execution" color="#EF4444" fdkey="worries" isMulti cmpItems={cmp("worries")} {...{showFullQ,countMode,n,cmpN,cmpMode,onPin:handlePin,onFilter:v=>handleFilter("worries",v)}}/>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
          <BarChart items={mfreq(rows,"channels")} title="Current channels" color="#8B82F0" fdkey="channels" isMulti maxShow={7} cmpItems={cmp("channels")} {...{showFullQ,countMode,n,cmpN,cmpMode,onPin:handlePin,onFilter:v=>handleFilter("channels",v)}}/>
          <BarChart items={mfreq(rows,"tried_channels")} title="Channels ever tried" color="#6366F1" fdkey="tried_channels" isMulti maxShow={8} cmpItems={cmp("tried_channels")} {...{showFullQ,countMode,n,cmpN,cmpMode,onPin:handlePin,onFilter:v=>handleFilter("tried_channels",v)}}/>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
          <PieChart items={freq(rows.filter(r=>r.nature_affects).map(r=>r.nature_affects))} title="Nature affects advertising (2)" fdkey="nature_affects" sm={NS} cmpItems={cmp("nature_affects")} {...{showFullQ,countMode,n,cmpN,cmpMode,onPin:handlePin,currentVal:F.nature_affects,onFilter:v=>handleFilter("nature_affects",v)}}/>
          <PieChart items={freq(rows.map(r=>r.involvement))} title="Desired involvement" fdkey="involvement" sm={IS} cmpItems={cmp("involvement")} {...{showFullQ,countMode,n,cmpN,cmpMode,onPin:handlePin,currentVal:F.involvement,onFilter:v=>handleFilter("involvement",v)}}/>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
          <BarChart items={freq(rows.map(r=>r.industry)).slice(0,9)} title="Industry" color="#F59E0B" fdkey="industry" cmpItems={cmp("industry")} {...{showFullQ,countMode,n,cmpN,cmpMode,onPin:handlePin,onFilter:v=>handleFilter("industry",v)}}/>
          <BarChart items={freq(rows.map(r=>r.tenure))} title="Business tenure" color="#34D399" fdkey="tenure" cmpItems={cmp("tenure")} {...{showFullQ,countMode,n,cmpN,cmpMode,onPin:handlePin,onFilter:v=>handleFilter("tenure",v)}}/>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
          <BarChart items={freq(rows.map(r=>r.revenue))} title="Annual revenue" color="#FCD34D" fdkey="revenue" cmpItems={cmp("revenue")} {...{showFullQ,countMode,n,cmpN,cmpMode,onPin:handlePin,onFilter:v=>handleFilter("revenue",v)}}/>
          <BarChart items={freq(rows.map(r=>r.operation))} title="How they operate" color="#60A5FA" fdkey="operation" cmpItems={cmp("operation")} {...{showFullQ,countMode,n,cmpN,cmpMode,onPin:handlePin,onFilter:v=>handleFilter("operation",v)}}/>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
          <BarChart items={freq(rows.map(r=>r.region))} title="Region" color="#FB7185" fdkey="region" cmpItems={cmp("region")} {...{showFullQ,countMode,n,cmpN,cmpMode,onPin:handlePin,onFilter:v=>handleFilter("region",v)}}/>
          <BarChart items={freq(rows.map(r=>r.gender))} title="Gender" color="#C4B5FD" fdkey="gender" cmpItems={cmp("gender")} {...{showFullQ,countMode,n,cmpN,cmpMode,onPin:handlePin,onFilter:v=>handleFilter("gender",v)}}/>
        </div>
      </div>

      {/* Open-ended drawer */}
      {drawerOpen && (
        <div style={{position:"fixed",right:0,top:0,bottom:0,width:420,background:"var(--bg,#fff)",borderLeft:"0.5px solid var(--bd2,#ccc)",zIndex:200,display:"flex",flexDirection:"column",boxShadow:"-4px 0 20px rgba(0,0,0,.1)"}}>
          <div style={{padding:"13px 15px",borderBottom:"0.5px solid var(--bd,#e2e2e2)",display:"flex",alignItems:"center",justifyContent:"space-between",fontSize:13,fontWeight:500,flexShrink:0}}>
            <span>Open-ended responses <span style={{fontSize:10,padding:"2px 6px",borderRadius:20,background:"#D1FAE5",color:"#065F46",fontWeight:500}}>{filteredOe.length}</span></span>
            <div style={{display:"flex",gap:8,alignItems:"center"}}>
              <input value={drawerSearch} onChange={e=>setDrawerSearch(e.target.value)}
                placeholder="Search..." style={{fontSize:12,padding:"4px 9px",border:"0.5px solid var(--bd2,#ccc)",borderRadius:6,background:"var(--bg,#fff)",color:"var(--tx,#111)",width:150,outline:"none"}}/>
              <button onClick={()=>setDrawerOpen(false)} style={{fontSize:14,background:"transparent",border:"none",cursor:"pointer",color:"var(--tx2,#555)"}}>✕</button>
            </div>
          </div>
          <div style={{flex:1,overflowY:"auto",padding:"10px 14px"}}>
            {filteredOe.slice(0,150).map((r,i) => (
              <div key={i} style={{padding:"9px 0",borderBottom:"0.5px solid var(--bd,#e2e2e2)"}}>
                <div style={{fontSize:11,color:"var(--tx3,#999)",marginBottom:3}}>
                  {r.survey==="v5"?"Original SMB (1)":"Online/Hybrid (2)"} · {ht(r.industry||"",22)} · {GS[r.gut]||ht(r.gut||"",20)}
                </div>
                <div style={{fontSize:12.5,color:"var(--tx,#111)",lineHeight:1.6}}>{String(r.open_ended)}</div>
              </div>
            ))}
            {filteredOe.length>150&&<div style={{color:"var(--tx3,#999)",fontSize:12,padding:12}}>Showing 150 of {filteredOe.length}. Use search to narrow down.</div>}
          </div>
        </div>
      )}

      <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
    </div>
  );
}